import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.RUW_BASIS_TWEEDE_PENSIOENPIJLER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY;

@Slf4j
public class BerekenPens2Antwerpen extends BerekenSocialeBijdragenDmfappl {

    public static final int AFRONDING = 2;
    public static final int MAANDEN_IN_KWARTAAL = 3;

    private static final int GRENS_LEEFTIJD = 35;
    private static final LocalDateTime START_PENS_ANTWERPEN = new LocalDateTime(2017, 4, 12, 12, 0);

    private static final Set<Sleutel<?>> BIJDRAGE_RSZ_SLEUTEL = ImmutableSet.of(
            SleutelWerkgeversCategorie.INSTANCE,
            SleutelWerknemersKengetal.INSTANCE,
            SleutelPensioenStelsel.INSTANCE,
            SleutelVerminderingsCode.INSTANCE);

    public BerekenPens2Antwerpen(ConstantManager constantManager, NlpGlobalService globalService) {
        super(constantManager, globalService);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getRekenTijd();
        int typeBijdrage = constantManager.getActualConstant(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd).getInteger();
        if (typeBijdrage == PensioenPijler2TypeBijdrage.ANTWERPEN.getCode()) {
            //Dit is check voor het regressie testen.
            if (rekenTijd.rekenTijdstip.isBefore(START_PENS_ANTWERPEN)) {
                LoonElementManager loonElementManager = mainContext.getLoonElementManager();
                Collection<LoonElement> loonElementen = loonElementManager.getPersoonsElementen();
                RekenTools.deleteKey(loonElementen, BASIS_TWEEDE_PENSIOENPIJLER_KEY);
                return CONTINUE_PROCESSING;
            }
            Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
            boolean jongerDan35 = isJongerDanGrens(persoon, rekenTijd);
            bepaalBasis(mainContext);
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
                bepaalBijdrage(opdrachtContext, opdracht, jongerDan35);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void bepaalBasis(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getRekenTijd();
        PersoonsDataManager dataManager = mainContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        LoonElementManager loonElementManager = mainContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = loonElementManager.getPersoonsElementen();
        Money basisPens2 = RekenTools.getSomProperty(BASIS_TWEEDE_PENSIOENPIJLER_KEY, loonElementen);
        Money basisPens2OnderGrensOther = dataManager.getBasisTweedePensioenPijlerOther();
        Money basisPens2BovenGrensOther = dataManager.getBasisBonusTweedePensioenPijlerOther();
        Money basisTotaalOther = basisPens2OnderGrensOther.add(basisPens2BovenGrensOther);
        Money basisTotaal = basisTotaalOther.add(basisPens2);
        Money grens = constantManager.getActualConstant(Konstanten.KST_BIJDRAGE_PENS2_GRENSBEDRAG_ANTWERPEN, rekenTijd).getMoney();

        Money basisOnderGrens;
        Money basisBovenGrens;

        if (basisTotaal.compareTo(grens) <= 0) {
            basisBovenGrens = grens.subtract(basisTotaalOther).min(Money.ZERO);
            basisOnderGrens = basisPens2.subtract(basisBovenGrens);
        } else {
            basisOnderGrens = grens.subtract(basisPens2OnderGrensOther).max(Money.ZERO);
            basisBovenGrens = basisPens2.subtract(basisOnderGrens);
        }

        RegulManager regulManager = mainContext.getRegulManager();
        if ((basisTotaal.compareTo(grens) > 0 && !basisPens2OnderGrensOther.add(basisOnderGrens).equals(grens))
                || (basisTotaal.compareTo(grens) <= 0 && basisPens2BovenGrensOther.add(basisBovenGrens).signum() != 0)) {
            Set<LocalDate> datums = dataManager.getGerekendeMaandenPatronaleBijdrageTweedePensioenPijlerOther();
            for (LocalDate datum : datums) {
                regulManager.addRegul(datum, null, Regulkode.HERREKENEN_NOODZAKELIJK);
            }
        }
        RekenTools.replaceKey(loonElementen, BASIS_TWEEDE_PENSIOENPIJLER_KEY, RUW_BASIS_TWEEDE_PENSIOENPIJLER_KEY);

        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(BASIS_TWEEDE_PENSIOENPIJLER_KEY, basisOnderGrens,
                RUW_BASIS_TWEEDE_PENSIOENPIJLER_KEY, basisPens2, loonElementen);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, basisBovenGrens,
                RUW_BASIS_TWEEDE_PENSIOENPIJLER_KEY, basisPens2, loonElementen);
    }

    private void bepaalBijdrage(RekenContext opdrachtContext, Opdracht opdracht, boolean jongerDan35) {
        SleutelSamenNemer aggregatorBijdrage = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregatorBijdrage.neemSamenVoorSleutel(opdracht, BIJDRAGE_RSZ_SLEUTEL);

        berekenBijdragePens2Antwerpen(opdrachtContext, BASIS_TWEEDE_PENSIOENPIJLER_KEY, PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, aggregaten,
                true, jongerDan35);
        berekenBijdragePens2Antwerpen(opdrachtContext, RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY,
                aggregaten, false, jongerDan35);

        berekenBijdrage(opdrachtContext, PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY,
                RekenPatronaalRszKey.BIJZONDERE_PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, aggregaten);
        berekenBijdrage(opdrachtContext, PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY,
                RekenPatronaalRszKey.BEHEERSKOSTEN_PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, aggregaten);

        berekenBijdrage(opdrachtContext, PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY,
                RekenPatronaalRszKey.BIJZONDERE_PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY, aggregaten);
        berekenBijdrage(opdrachtContext, PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY,
                RekenPatronaalRszKey.BEHEERSKOSTEN_PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY, aggregaten);
    }

    private void berekenBijdragePens2Antwerpen(
            RekenContext opdrachtContext, MoneyKey basisKey, MoneyKey bijdrageKey, List<SleutelGegevens> aggregaten,
            boolean onderGrens, boolean jongerDan35) {
        boolean gegevensVorigKwartaal = opdrachtContext.getBoolean(RekenChainKey.RSZ_VORIG_KWARTAAL_KEY);
        if (gegevensVorigKwartaal) {
            LocalDate selectieVorigKwartaal = opdrachtContext.getUnchecked(RekenChainKey.SELECTIE_DATUM_VORIG_KWARTAAL_KEY);
            Opper opperVorigKwartaal = opdrachtContext.getUnchecked(RekenChainKey.OPPER_VORIG_KWARTAAL_KEY);
            berekenBijdragePens2AntwerpenVorigKwartaal(opdrachtContext, basisKey, bijdrageKey, onderGrens, jongerDan35, selectieVorigKwartaal, opperVorigKwartaal);
        } else {
            berekenBijdragePens2AntwerpenNormaal(opdrachtContext, basisKey, bijdrageKey, aggregaten, onderGrens, jongerDan35);
        }
    }

    private void berekenBijdragePens2AntwerpenNormaal(
            RekenContext context, MoneyKey basisKey, MoneyKey bijdrageKey, List<SleutelGegevens> aggregaten, boolean onderGrens, boolean jongerDan35) {
        log.debug("berekenBijdrage(context,\"{}\",\"{}\",agregaten)", basisKey, bijdrageKey);
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonElementManager manager = context.getLoonElementManager();
        RegulManager regulManager = context.getRegulManager();
        BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
        Money bijdrageTotaal = Money.ZERO;
        for (SleutelGegevens aggregaat : aggregaten) {
            Collection<LoonElement> opperElementen = aggregaat.getOpperElementen(manager);
            LocalDate zoekDatum = TimeTools.getZoekDatum(aggregaat, rekenTijd.rekenPeriode);
            Money bijdrage = berekenBijdragePens2Antwerpen(basisKey, bijdrageKey, opperElementen, aggregaat, bijdragePercentages, zoekDatum, onderGrens, jongerDan35);
            bijdrageTotaal = bijdrageTotaal.add(bijdrage);

            log.trace("aggregaatElementen:{}", opperElementen);
        }
        context.put(bijdrageKey, bijdrageTotaal.round(AFRONDING));
    }

    private static Money berekenBijdragePens2Antwerpen(
            MoneyKey basisKey, MoneyKey bijdrageKey, Collection<LoonElement> loonElementen,
            SleutelGegevens aggregaat, BijdragePercentages bijdragePercentages, LocalDate zoekDatum, boolean onderGrens, boolean jongerDan35) {
        Money basisSocialeBijdrage = RekenTools.getSomProperty(basisKey, loonElementen);

        Money bijdrage = Money.ZERO;
        log.debug("{} {}={}", aggregaat, basisKey, basisSocialeBijdrage);
        if (basisSocialeBijdrage.signum() != 0) {
            BigDecimal percentageBijdrage = bijdragePercentages.getPatronaleBijdrageTweedePensioenPijlerAntwerpen(aggregaat, zoekDatum, onderGrens, jongerDan35);
            bijdrage = basisSocialeBijdrage.multiply(percentageBijdrage);
            log.debug("percentage={},{}={}", percentageBijdrage, bijdrageKey, bijdrage);
            PercentageBasisVormer.vormBedragAlsPercentageBasisPut(bijdrageKey, basisKey, percentageBijdrage, loonElementen);
            log.debug("{};basisKey \"{}\":{};bijdrageKey \"{}\":{}", LogTools.toSimpleLog(aggregaat), basisKey, basisSocialeBijdrage, bijdrageKey, bijdrage);
        }
        return bijdrage;
    }

    protected void berekenBijdragePens2AntwerpenVorigKwartaal(
            RekenContext context, MoneyKey basisKey, MoneyKey bijdrageKey, boolean onderGrens, boolean jongerDan35,
            LocalDate zoekDatumVorigKwartaal, Opper opperVorigKwartaal) {
        log.debug("berekenBijdragePens2AntwerpenVorigKwartaal(context,\"{}\",\"{}\",{},opperVorigKwartaal)", basisKey, bijdrageKey, zoekDatumVorigKwartaal);
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonElementManager manager = context.getLoonElementManager();
        RegulManager regulManager = context.getRegulManager();
        BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
        SleutelGegevens aggregaat = new SleutelGegevensSingleOpper(opperVorigKwartaal);

        Collection<LoonElement> opdrachtsElementen = manager.getOpdrachtsElementen(aggregaat.getOpdracht());
        Money bijdrageTotaal =
                berekenBijdragePens2Antwerpen(basisKey, bijdrageKey, opdrachtsElementen, aggregaat, bijdragePercentages, zoekDatumVorigKwartaal, onderGrens, jongerDan35);

        log.trace("opdrachtElementen:{}", opdrachtsElementen);
        context.put(bijdrageKey, bijdrageTotaal.round(AFRONDING));
    }

    private static boolean isJongerDanGrens(Persoon persoon, RekenTijd rekenTijd) {
        LocalDate geboorteDatum = persoon.getGeboorteDatum();
        int kwartaal = TimeTools.bepaalKwartaal(rekenTijd.beginDatum);
        LocalDate beginKwartaal = new LocalDate(rekenTijd.beginDatum.getYear(), 1 + (kwartaal - 1) * MAANDEN_IN_KWARTAAL, 1);
        int leeftijd = Years.yearsBetween(geboorteDatum, beginKwartaal).getYears();
        return leeftijd <= GRENS_LEEFTIJD;
    }

}
